// dbReady 标记本地 DB 是否可用；false 时所有用例 t.Skip。
var dbReady bool

func TestMain(m *testing.M) {
	// 切到项目根：业务代码用相对路径加载 app.toml/app_local.toml（config.WeChatConf 等）。
	// go test 默认 cwd 是包目录 tests/service，需回退两级到项目根，否则 MustLoad 找不到 app.toml。
	_ = os.Chdir("../..")

	if err := mysqls.EnableMysql(testDSN); err == nil && mysqls.DB() != nil {
		// 建表（幂等：已存在则跳过）+ 跑 activated_at 迁移
		_ = widgets.CreateModel("守护邀请表", model.Invitation{})
		_ = widgets.CreateModel("守护关系表", model.Guardianship{})
		_ = widgets.CreateModel("被守护人档案表", model.ElderProfile{})
		_ = widgets.CreateModel("小程序消息表", model.Message{})
		_ = widgets.AddColumnAfter(model.Guardianship{}, "ActivatedAt", "Status")
		// 与 migrate_center 对齐：补 invitation.city / elder_profile 联系电话列
		_ = widgets.AddColumnAfter(model.Invitation{}, "City", "RemindTime")
		_ = widgets.AddColumnAfter(model.ElderProfile{}, "ElderPhone", "Address")
		_ = widgets.AddColumnAfter(model.ElderProfile{}, "GuardianPhone", "ElderPhone")
		dbReady = true
	}
	os.Exit(m.Run())
}

// cleanTables 每个用例前清空相关表，保证用例间隔离。
func cleanTables(t *testing.T) {
	t.Helper()
	for _, tbl := range []string{"t_invitation", "t_guardianship", "t_elder_profile", "t_message"} {
		if err := mysqls.DB().Exec("DELETE FROM " + tbl).Error; err != nil {
			t.Fatalf("clean table %s: %v", tbl, err)
		}
	}
}

func requireDB(t *testing.T) {
	t.Helper()
	if !dbReady {
		t.Skip("local mysql unavailable, skip integration test")
	}
	cleanTables(t)
}

