// IT-11 首次接受且老人已有 ElderProfile：不重复建档案、建关系成功、ActivatedAt==nowMs
func TestAccept_IT11_ExistingProfile(t *testing.T) {
	requireDB(t)
	const code, guardian, elder = "code11", "guardianK", "elderK"
	var nowMs int64 = 1750000000000
	// 预先造一条 elder 档案
	if err := mysqls.DB().Create(&model.ElderProfile{
		UserId: elder, RealName: "张三", RemindTime: "08:00",
	}).Error; err != nil {
		t.Fatalf("IT-11 seed profile: %v", err)
	}
	seedInvitation(t, &model.Invitation{
		InvitationId: "inv11", InviteCode: code, GuardianUserId: guardian,
		Relation: model.RelationMom, RemindTime: "09:00",
		Status: model.InvitationStatusPending, ExpireAt: nowMs + 1000000,
	})
	if err := service.GetInvitationService().Accept(elder, code, nowMs); err != nil {
		t.Fatalf("IT-11 expected success, got %v", err)
	}
	// 档案仍只有一条、原 RealName 未被覆盖
	var cnt int64
	mysqls.DB().Model(&model.ElderProfile{}).Where("user_id = ?", elder).Count(&cnt)
	if cnt != 1 {
		t.Errorf("IT-11 elder profile count = %d, want 1 (不重复建)", cnt)
	}
	p, _ := mapper.GetElderProfileMapper().GetByUserId(elder)
	if p.RealName != "张三" {
		t.Errorf("IT-11 existing profile RealName overwritten: %s", p.RealName)
	}
	// 关系建成、ActivatedAt 正确
	g, _ := mapper.GetGuardianshipMapper().GetActive(guardian, elder)
	if g == nil || g.ActivatedAt != nowMs {
		t.Errorf("IT-11 guardianship wrong: %+v", g)
	}
}
